function Timer() {
  const [count, setCount] = useState(0);
  const [isRunning, setIsRunning] = useState(false);

  useEffect(() => {
    if (isRunning) {
      const id = setInterval(() => {
        setCount(count + 1);
      }, 1000);
      return () => clearInterval(id);
    }
  }, [isRunning]);

  return (
    <div>
      <span>{count}</span>
      <button onClick={() => setIsRunning(r => !r)}>Toggle</button>
    </div>
  );
}

